#include<bits/stdc++.h>
using namespace std;
long long n, m, num, num2;
bool a[10001][10001];
int main(){
	cin>>n>>m;
	for(int i=1;i<=n;i++){
		for(int j=1;j<=n;j++){
			cin>>a[i][j];
		}
	}
	for (int i = 1; i <= n; i++) {
		if (a[i][m] == 1) {
			num++;
		}
		if (a[m][i] == 1) {
			num2++;
		}
	}
	cout<<num2<<" "<<num<<" "<<num+num2;
	return 0;
}
